SELECT AVG(num_trades) AS avg_num_trades
FROM (
  SELECT user_id, COUNT(*) AS num_trades
  FROM trades
  GROUP BY user_id
) AS subquery;

SELECT COUNT(DISTINCT t.user_id) AS unique_traders, AVG(t.amount) AS average_haul
FROM trades t
WHERE t.date >= DATE('now', '-30 days');

SELECT AVG(market_price) AS avg_market_price
FROM market_data
WHERE date = (SELECT MAX(date) FROM market_data);

SELECT market_price, total_bitcoins, market_cap, trade_volume, block_size, date 
FROM market_data 
WHERE market_price > 8000 AND date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT COUNT(*) AS total_news
FROM news
WHERE date >= DATE('now', '-7 days');

SELECT role, COUNT(*) AS total_users
FROM users
GROUP BY role;
